const ICON_SIZE = 32;
// Half the typical aircraft length (~60m fuselage) so on-ground icons sit on the surface
const GROUND_OFFSET_M = 30;

const categoryIconUrls: { [key: number]: string } = {
  2: '/aircraft-icons/Light%20Aircraft.png',
  3: '/aircraft-icons/Small%20Jets.png',
  4: '/aircraft-icons/Large%20Commercial.png',
  6: '/aircraft-icons/Heavy%20Jets.png',
  7: '/aircraft-icons/High%20Performance.png',
  8: '/aircraft-icons/Helicopters.png',
  14: '/aircraft-icons/UAVs%20Drones.png'
};

const getAircraftIconUrl = (categoryId: number): string => {
  return categoryIconUrls[categoryId] ?? categoryIconUrls[2];
};

// ── Canvas-drawn label helper ──────────────────────────────────────────────
// Draws the callsign text onto an off-screen canvas and returns a data URL.
// Because we control every pixel ourselves this is completely font-scaling
// and DPI agnostic — output is identical in Chrome, Brave, Firefox, Safari.
const _lblCache = new Map<string, { url: string; w: number; h: number }>();

function makeTextLabel(text: string): { url: string; w: number; h: number } {
  if (_lblCache.has(text)) return _lblCache.get(text)!;
  const FONT_PX = 11;
  const PAD_X = 6;
  const PAD_Y = 3;
  const c = document.createElement('canvas');
  const ctx = c.getContext('2d')!;
  ctx.font = `${FONT_PX}px Arial, Helvetica, sans-serif`;
  const tw = Math.ceil(ctx.measureText(text).width);
  c.width  = tw + PAD_X * 2;
  c.height = FONT_PX + PAD_Y * 2;
  // Must re-set font after canvas resize (resize clears 2D state)
  ctx.font = `${FONT_PX}px Arial, Helvetica, sans-serif`;
  ctx.fillStyle = 'rgba(0,0,0,0.78)';
  ctx.fillRect(0, 0, c.width, c.height);
  ctx.fillStyle = '#ffffff';
  ctx.textBaseline = 'top';
  ctx.fillText(text, PAD_X, PAD_Y);
  const result = { url: c.toDataURL(), w: c.width, h: c.height };
  _lblCache.set(text, result);
  return result;
}

const createIconCanvas = (draw: (ctx: CanvasRenderingContext2D) => void): HTMLCanvasElement => {
  const canvas = document.createElement('canvas');
  canvas.width = ICON_SIZE;
  canvas.height = ICON_SIZE;
  const ctx = canvas.getContext('2d')!;

  ctx.clearRect(0, 0, ICON_SIZE, ICON_SIZE);
  draw(ctx);

  return canvas;
};

const setStroke = (ctx: CanvasRenderingContext2D) => {
  ctx.fillStyle = '#ffffff';
  ctx.strokeStyle = '#000000';
  ctx.lineWidth = 1.5;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
};

const drawLightAircraft = (ctx: CanvasRenderingContext2D, color: Color) => {
  setStroke(ctx);
  // Propeller circle at front
  ctx.beginPath();
  ctx.arc(4, 12, 2.5, 0, Math.PI * 2);
  ctx.stroke();

  // Nose cone
  ctx.beginPath();
  ctx.moveTo(6, 10);
  ctx.lineTo(10, 10);
  ctx.lineTo(10, 14);
  ctx.lineTo(6, 14);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Main fuselage body (cockpit area wider)
  ctx.beginPath();
  ctx.moveTo(10, 9);
  ctx.lineTo(20, 8);
  ctx.lineTo(22, 10);
  ctx.lineTo(22, 14);
  ctx.lineTo(20, 16);
  ctx.lineTo(10, 15);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Tail section
  ctx.beginPath();
  ctx.moveTo(22, 11);
  ctx.lineTo(26, 11);
  ctx.lineTo(28, 12);
  ctx.lineTo(26, 13);
  ctx.lineTo(22, 13);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Low wing (swept back)
  ctx.beginPath();
  ctx.moveTo(12, 14);
  ctx.lineTo(14, 24);
  ctx.lineTo(16, 24);
  ctx.lineTo(18, 14);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Horizontal stabilizer (tail wing)
  ctx.beginPath();
  ctx.moveTo(24, 11);
  ctx.lineTo(24, 8);
  ctx.lineTo(28, 10);
  ctx.lineTo(28, 14);
  ctx.lineTo(24, 13);
  ctx.stroke();

  // Vertical stabilizer
  ctx.beginPath();
  ctx.moveTo(26, 12);
  ctx.lineTo(28, 6);
  ctx.lineTo(28, 12);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Landing gear
  ctx.beginPath();
  ctx.arc(14, 26, 1.5, 0, Math.PI * 2);
  ctx.fill();
  ctx.stroke();

  ctx.beginPath();
  ctx.moveTo(14, 15);
  ctx.lineTo(14, 24.5);
  ctx.stroke();

  // Cockpit window
  ctx.beginPath();
  ctx.arc(16, 10, 1.5, 0, Math.PI * 2);
  ctx.stroke();
};

const drawSmallJet = (ctx: CanvasRenderingContext2D, color: Color) => {
  setStroke(ctx);
  // Fuselage (streamlined)
  ctx.beginPath();
  ctx.moveTo(16, 4);
  ctx.lineTo(18, 20);
  ctx.lineTo(14, 20);
  ctx.lineTo(16, 4);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Swept wings
  ctx.beginPath();
  ctx.moveTo(6, 14);
  ctx.lineTo(16, 12);
  ctx.lineTo(16, 14);
  ctx.lineTo(6, 16);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  ctx.beginPath();
  ctx.moveTo(26, 14);
  ctx.lineTo(16, 12);
  ctx.lineTo(16, 14);
  ctx.lineTo(26, 16);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // T-tail
  ctx.beginPath();
  ctx.moveTo(16, 20);
  ctx.lineTo(16, 26);
  ctx.stroke();

  ctx.beginPath();
  ctx.moveTo(12, 24);
  ctx.lineTo(20, 24);
  ctx.lineTo(20, 26);
  ctx.lineTo(12, 26);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Rear-mounted engines
  ctx.beginPath();
  ctx.arc(12, 18, 1.5, 0, Math.PI * 2);
  ctx.fill();
  ctx.stroke();

  ctx.beginPath();
  ctx.arc(20, 18, 1.5, 0, Math.PI * 2);
  ctx.fill();
  ctx.stroke();
};

const drawLargeCommercial = (ctx: CanvasRenderingContext2D, color: Color) => {
  setStroke(ctx);
  // Fuselage (wide body)
  ctx.beginPath();
  ctx.moveTo(16, 4);
  ctx.lineTo(20, 22);
  ctx.lineTo(18, 26);
  ctx.lineTo(14, 26);
  ctx.lineTo(12, 22);
  ctx.lineTo(16, 4);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Cockpit windows
  ctx.beginPath();
  ctx.arc(16, 6, 1.5, 0, Math.PI * 2);
  ctx.stroke();

  // Window line along fuselage
  ctx.beginPath();
  ctx.moveTo(14, 10);
  ctx.lineTo(14, 18);
  ctx.stroke();

  ctx.beginPath();
  ctx.moveTo(18, 10);
  ctx.lineTo(18, 18);
  ctx.stroke();

  // Swept wings
  ctx.beginPath();
  ctx.moveTo(4, 18);
  ctx.lineTo(16, 14);
  ctx.lineTo(16, 16);
  ctx.lineTo(4, 20);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  ctx.beginPath();
  ctx.moveTo(28, 18);
  ctx.lineTo(16, 14);
  ctx.lineTo(16, 16);
  ctx.lineTo(28, 20);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Under-wing engines
  ctx.beginPath();
  ctx.arc(8, 20, 2.5, 0, Math.PI * 2);
  ctx.fill();
  ctx.stroke();

  ctx.beginPath();
  ctx.arc(24, 20, 2.5, 0, Math.PI * 2);
  ctx.fill();
  ctx.stroke();

  // Tail fin
  ctx.beginPath();
  ctx.moveTo(16, 22);
  ctx.lineTo(16, 28);
  ctx.lineTo(18, 26);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();
};

