const drawDrone = (ctx: CanvasRenderingContext2D, color: Color) => {
  setStroke(ctx);
  ctx.lineWidth = 2;
  // Outer triangle body
  ctx.beginPath();
  ctx.moveTo(16, 2);
  ctx.lineTo(30, 30);
  ctx.lineTo(2, 30);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();
  
  ctx.lineWidth = 1.5;
  // Inner triangle detail
  ctx.beginPath();
  ctx.moveTo(16, 10);
  ctx.lineTo(22, 20);
  ctx.lineTo(10, 20);
  ctx.closePath();
  ctx.stroke();
  
  // Camera lens center (multiple concentric circles)
  ctx.beginPath();
  ctx.arc(16, 17, 4, 0, Math.PI * 2);
  ctx.fill();
  ctx.stroke();
  
  ctx.beginPath();
  ctx.arc(16, 17, 2.5, 0, Math.PI * 2);
  ctx.fill();
  ctx.stroke();
  
  ctx.beginPath();
  ctx.arc(16, 17, 1, 0, Math.PI * 2);
  ctx.fill();
  ctx.stroke();
  
  // Orbital ring around camera (partial arcs)
  ctx.beginPath();
  ctx.arc(16, 17, 6, -0.5, 0.5);
  ctx.stroke();
  
  ctx.beginPath();
  ctx.arc(16, 17, 6, Math.PI - 0.5, Math.PI + 0.5);
  ctx.stroke();
  
  // Small indicator dot above camera
  ctx.beginPath();
  ctx.arc(16, 8, 0.8, 0, Math.PI * 2);
  ctx.fill();
};

interface CesiumViewerProps {
  aircraft: Aircraft[];
  selectedAircraft: Aircraft | null;
  maxDisplayCount: number;
  viewMode: 'global' | 'follow' | 'cockpit' | 'approach' | 'satellite';
  showLabels?: boolean;
  showPaths?: boolean;
  enabledCategories?: Set<number>;
  onSelectAircraft?: (aircraft: Aircraft) => void;
  onDeselectAircraft?: () => void;
  onViewModeChange?: (mode: 'global' | 'follow' | 'cockpit' | 'approach' | 'satellite') => void;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error?: Error;
}

interface ErrorBoundaryProps {
  children: ReactNode;
}

class CesiumErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Cesium Viewer Error:', error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="cesium-container h-full flex items-center justify-center bg-gray-900">
          <div className="text-center p-8 max-w-md">
            <div className="text-red-400 text-4xl mb-4">⚠️</div>
            <h2 className="text-xl font-semibold mb-2 text-white">3D Viewer Error</h2>
            <p className="text-gray-400 mb-4">
              Failed to initialize the 3D globe viewer. This might be due to missing assets or configuration issues.
            </p>
            <button
              onClick={() => window.location.reload()}
              className="bg-blue-600 hover:bg-blue-700 px-6 py-2 rounded-lg text-white"
            >
              Reload Page
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

const CesiumViewer: React.FC<CesiumViewerProps> = ({
  aircraft,
  selectedAircraft,
  maxDisplayCount = 100,
  viewMode = 'global',
  showLabels = true,
  showPaths = false,
  enabledCategories,
  onSelectAircraft,
  onDeselectAircraft,
  onViewModeChange
}) => {
  const viewerRef = useRef<any>(null);
  const creditContainerRef = useRef<HTMLDivElement>(document.createElement('div'));
  const previousAircraftRef = useRef<Map<string, Aircraft>>(new Map());
  const aircraftPathsRef = useRef<Map<string, Cartesian3[]>>(new Map());
  const [showSatelliteHint, setShowSatelliteHint] = useState(false);
  const [showGlobalHint, setShowGlobalHint] = useState(false);
  const [aircraftEverLoaded, setAircraftEverLoaded] = useState(false);
  const [zoomAltitude, setZoomAltitude] = useState<number | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [imageryStatus, setImageryStatus] = useState<'loading' | 'ion3' | 'google' | 'osm' | 'default'>('loading');
  const [atmosphereEnabled, setAtmosphereEnabled] = useState(true);
  const [loadingMessage, setLoadingMessage] = useState('Configuring Cesium...');
  const [showLoadingOverlay, setShowLoadingOverlay] = useState(true);
  const aircraftMotionDataRef = useRef<Map<string, {
    prevPos: Cartesian3,
    currentPos: Cartesian3,
    updateTime: any,
    prevUpdateTime: any,
    heading: number,
    altitude: number,
    velocity: number,
    verticalRate: number,
    lastSampleTime: number
  }>>(new Map());
  
  // Track aircraft by ICAO24 to detect actual changes
  const previousAircraftDataRef = useRef<Map<string, {lat: number, lon: number, alt: number}>>(new Map());
  // Track last seen timestamps so we don't immediately remove entities
  const lastSeenRef = useRef<Map<string, number>>(new Map());
  // Track icao24 → category so we can instantly remove filtered-out aircraft
  const aircraftCategoryRef = useRef<Map<string, number>>(new Map());
  // Track approach zoom level so user scroll is preserved
  const approachZoomRef = useRef<number>(2000);
  // Track satellite follow: icao24 of aircraft being followed (null = wide overview)
  const satelliteFollowRef = useRef<string | null>(null);
  // Track satellite zoom level so user scroll is preserved
  const satelliteZoomRef = useRef<number>(4000);
  // True while the initial fly-to animation is running; rAF skips setView during this time
  const satelliteAnimatingRef = useRef<boolean>(false);
  // Legacy ref — kept for compatibility
  const prevViewModeRef = useRef<string>(viewMode);

  // Initialize Cesium when viewer is ready — poll until cesiumElement is available
  // (Resium sets cesiumElement slightly after React's useEffect fires on first mount)
  useEffect(() => {
    let pollId: ReturnType<typeof setTimeout>;
    let cancelled = false;

    // Safety timeout: force-hide overlay after 8s regardless
    const overlayFailSafe = setTimeout(() => {
      setImageryStatus((prev) => (prev === 'loading' ? 'default' : prev));
      setLoadingMessage('Default imagery in use');
      setShowLoadingOverlay(false);
    }, 8000);

    const initViewer = (viewer: Cesium.Viewer) => {
      if (cancelled) return;
      console.log('Cesium Ion token:', CESIUM_ION_TOKEN ? 'Set ✓' : 'Missing ✗');

      // Keep render loop running so all aircraft interpolate smoothly even while following one
      viewer.clock.shouldAnimate = true;
      viewer.scene.requestRenderMode = false;
      viewer.useDefaultRenderLoop = true;
      viewer.scene.maximumRenderTimeChange = 0; // render every frame when possible
      viewer.targetFrameRate = 60;
      viewer.clock.multiplier = 1;

      // ── Globe visuals ──────────────────────────────────────────────
      viewer.scene.globe.enableLighting = true;
      viewer.scene.globe.depthTestAgainstTerrain = false; // true causes addTrianglesToChildrenNodes crash without a real terrain provider
      viewer.scene.globe.showGroundAtmosphere = true;
      viewer.scene.globe.showSkirts = true;
      viewer.scene.globe.atmosphereLightIntensity = 10.0;
      viewer.scene.globe.atmosphereMieAnisotropy = 0.9;

      // Space / atmosphere visuals — gives the blue halo & star field
      if (viewer.scene.skyAtmosphere) {
        viewer.scene.skyAtmosphere.show = true;
        viewer.scene.skyAtmosphere.atmosphereLightIntensity = 10.0;
      }
      if (viewer.scene.skyBox) {
        (viewer.scene.skyBox as any).show = true;
      }
      viewer.scene.backgroundColor = Cesium.Color.BLACK;
      if (!viewer.scene.sun) viewer.scene.sun = new Cesium.Sun();
      if (!viewer.scene.moon) viewer.scene.moon = new Cesium.Moon();

      // ── Imagery: async Ion asset load ──────────────────────────────
      // Asset 3 = Bing Maps Aerial with Labels (country/city/road names) — same as reference HTML
      (async () => {
        console.log('Starting imagery load for Ion asset 3');
        setImageryStatus('loading');
        setLoadingMessage('Fetching imagery from Ion (asset 3)...');
        const failover = setTimeout(() => {
          if (imageryStatus === 'loading') {
            console.warn('Imagery load taking too long — default imagery in use');
            setImageryStatus('default');
            setLoadingMessage('Using default imagery');
            setTimeout(() => setShowLoadingOverlay(false), 800);
          }
        }, 10000);
        try {
          const imageryProvider = await Cesium.IonImageryProvider.fromAssetId(3);
          viewer.imageryLayers.removeAll();
          viewer.imageryLayers.addImageryProvider(imageryProvider);
          clearTimeout(failover);
          setImageryStatus('ion3');
          setLoadingMessage('✅ Asset 3 loaded');
          console.log('Ion asset 3 (Bing Aerial with Labels) loaded ✓');
          setTimeout(() => setShowLoadingOverlay(false), 800);
        } catch (err) {
          clearTimeout(failover);
          console.error('Ion asset 3 load failed', err);
          setLoadingMessage('Ion asset 3 failed — trying Google');
          try {
            // Fallback: Google Maps satellite
            const googleProvider = await Cesium.IonImageryProvider.fromAssetId(3830183);
            viewer.imageryLayers.removeAll();
            viewer.imageryLayers.addImageryProvider(googleProvider);
            setImageryStatus('google');
            console.log('Google Maps imagery loaded ✓');
            setLoadingMessage('Google imagery loaded');
            setTimeout(() => setShowLoadingOverlay(false), 800);
          } catch (err2) {
            console.error('Google fallback load failed', err2);
            setLoadingMessage('Google failed — trying OSM');
            try {
              // Final fallback: OpenStreetMap tiles (keeps labels without Ion)
              const osmProvider = new Cesium.UrlTemplateImageryProvider({
                url: 'https://tile.openstreetmap.org/{z}/{x}/{y}.png',
                credit: '© OpenStreetMap contributors'
              });
              viewer.imageryLayers.removeAll();
              viewer.imageryLayers.addImageryProvider(osmProvider);
              setImageryStatus('osm');
              console.warn('OSM imagery fallback loaded ✓');
              setLoadingMessage('OSM imagery loaded');
              setTimeout(() => setShowLoadingOverlay(false), 800);
            } catch (err3) {
              console.error('OSM fallback load failed', err3);
              // Keep Cesium default imagery (Natural Earth with labels)
              setImageryStatus('default');
              console.warn('All imagery unavailable — using Cesium default imagery');
              setLoadingMessage('Default imagery in use');
              setTimeout(() => setShowLoadingOverlay(false), 800);
            }
          }
        }
      })();

      // Set initial view — Africa/Atlantic centered, Europe at top
      viewer.camera.setView({
        destination: Cartesian3.fromDegrees(10, 15, 18000000),
        orientation: {
          heading: 0,
          pitch: -CesiumMath.PI_OVER_TWO,
          roll: 0
        }
      });

      if (viewer.scene.skyAtmosphere) {
        setAtmosphereEnabled(viewer.scene.skyAtmosphere.show !== false);
      }

      console.log('Cesium viewer initialized ✓');
    };

    // Poll every 100ms until cesiumElement is available, then run init once.
    // Resium assigns cesiumElement slightly after React's first useEffect fires.
    const poll = () => {
      if (cancelled) return;
      const el = viewerRef.current?.cesiumElement;
      if (el) {
        clearTimeout(overlayFailSafe);
        // Reset the failsafe now that we know the viewer is ready
        const newFailSafe = setTimeout(() => {
          setImageryStatus((prev) => (prev === 'loading' ? 'default' : prev));
          setLoadingMessage('Default imagery in use');
          setShowLoadingOverlay(false);
        }, 8000);
        initViewer(el);
        // Clean up the new failsafe on unmount via the outer cancel flag
        pollId = newFailSafe;
      } else {
        pollId = setTimeout(poll, 100);
      }
    };
    poll();

    return () => {
      cancelled = true;
      clearTimeout(pollId);
      clearTimeout(overlayFailSafe);
    };
  }, []);

  const handleResetView = () => {
    const viewer = viewerRef.current?.cesiumElement;
    if (!viewer) return;
    viewer.camera.flyTo({
      destination: Cartesian3.fromDegrees(10, 15, 18000000),
      orientation: {
        heading: 0,
        pitch: -CesiumMath.PI_OVER_TWO,
        roll: 0.0
      },
      duration: 2
    });
  };

  const handleToggleAtmosphere = () => {
    const viewer = viewerRef.current?.cesiumElement;
    if (!viewer || !viewer.scene.skyAtmosphere) return;
    const next = !viewer.scene.skyAtmosphere.show;
    viewer.scene.skyAtmosphere.show = next;
    viewer.scene.globe.showGroundAtmosphere = next;
    setAtmosphereEnabled(next);
  };

  const handleToggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.body.requestFullscreen?.();
    } else {
      document.exitFullscreen?.();
    }
  };

  // Update aircraft entities with proper animation
  useEffect(() => {
    if (!viewerRef.current?.cesiumElement) return;

    const viewer = viewerRef.current.cesiumElement;
    const checkedViewer = viewer as any;
    
    if (!checkedViewer.entities) {
      console.error('Cesium viewer entities collection not ready');
      return;
    }

    const displayAircraft = aircraft.slice(0, maxDisplayCount);
    console.log(`Updating ${displayAircraft.length} aircraft`);

    // Store current time for all updates
    const nowJulian = Cesium.JulianDate.now();
    const nowSec = Date.now() / 1000;
    // How long to interpolate between updates (seconds)
    const interpolationDuration = 10.5;

    // Track current batch of aircraft
    const newPreviousAircraft = new Map();
    let updatedCount = 0;

    const earthRadius = 6378137; // meters

    // Returns the aircraft's current projected position using phased motion:
    // Phase 1 (elapsed < total): pure lerp from prevPos → currentPos — no dead-reckoning.
    // Phase 2 (elapsed ≥ total): pure dead-reckoning forward from currentPos using velocity.
    // This NEVER double-counts movement so aircraft never overshoot, stop or go backwards.
    const getProjectedPosition = (data: {
      prevPos: Cartesian3,
      currentPos: Cartesian3,
      updateTime: any,
      prevUpdateTime: any,
      heading: number,
      altitude: number,
      velocity: number,
      verticalRate: number,
      lastSampleTime: number
    }) => {
      const elapsed = Cesium.JulianDate.secondsDifference(nowJulian, data.prevUpdateTime);
      const total = Cesium.JulianDate.secondsDifference(data.updateTime, data.prevUpdateTime) || interpolationDuration;
      const currCarto = Cesium.Cartographic.fromCartesian(data.currentPos);
      const headingRad = Cesium.Math.toRadians(data.heading || 0);
      const speed = data.velocity || 0;
      const climb = data.verticalRate || 0;

      if (elapsed < total) {
        // Phase 1: lerp only
        const t = Math.max(0, elapsed / total);
        const prevCarto = Cesium.Cartographic.fromCartesian(data.prevPos);
        return Cartesian3.fromRadians(
          prevCarto.longitude + (currCarto.longitude - prevCarto.longitude) * t,
          prevCarto.latitude  + (currCarto.latitude  - prevCarto.latitude)  * t,
          prevCarto.height    + (currCarto.height    - prevCarto.height)    * t
        );
      } else {
        // Phase 2: dead-reckon forward from currentPos
        const dtSec = Math.min(elapsed - total, 60); // cap at 60 s to avoid runaway
        const dLat = (speed * Math.cos(headingRad) * dtSec) / earthRadius;
        const dLon = (speed * Math.sin(headingRad) * dtSec) / (earthRadius * Math.max(Math.cos(currCarto.latitude), 1e-6));
        return Cartesian3.fromRadians(
          currCarto.longitude + dLon,
          currCarto.latitude  + dLat,
          currCarto.height    + climb * dtSec
        );
      }
    };

    displayAircraft.forEach((plane) => {
      try {
        // Skip invalid positions
        if (!plane.latitude || !plane.longitude || isNaN(plane.latitude) || isNaN(plane.longitude)) {
          return;
        }

        const altitude = plane.baro_altitude || plane.geo_altitude || 0;
        // Lift on-ground aircraft so the icon sits on the surface instead of half-buried
        const effectiveAlt = (plane.on_ground || altitude < GROUND_OFFSET_M)
          ? GROUND_OFFSET_M
          : altitude;
        
        // Check if aircraft position has actually changed significantly
        const prevData = previousAircraftDataRef.current.get(plane.icao24);
        const positionChanged = !prevData || 
          Math.abs(prevData.lat - plane.latitude) > 0.0001 || 
          Math.abs(prevData.lon - plane.longitude) > 0.0001 ||
          Math.abs(prevData.alt - altitude) > 100; // 100m altitude change threshold
        

        if (!positionChanged) {
          newPreviousAircraft.set(plane.icao24, plane);
          return; // Skip update if position hasn't actually changed
        }
        
        updatedCount++;
        const newPos = Cartesian3.fromDegrees(plane.longitude, plane.latitude, Math.min(effectiveAlt, 15000));
        // mark last seen time and category for this aircraft
        lastSeenRef.current.set(plane.icao24, Date.now());
        aircraftCategoryRef.current.set(plane.icao24, plane.category ?? -1);
        
        // Store position data
        previousAircraftDataRef.current.set(plane.icao24, {
          lat: plane.latitude,
          lon: plane.longitude,
          alt: effectiveAlt
        });
        
        // Get existing motion data
        let motionData = aircraftMotionDataRef.current.get(plane.icao24);
        
        if (!motionData) {
          // First time seeing this aircraft: initialize times so the next update
          // will produce a smooth interpolation window.
          const prevTime = nowJulian;
          const targetTime = Cesium.JulianDate.addSeconds(nowJulian, interpolationDuration, new Cesium.JulianDate());

          motionData = {
            prevPos: newPos,
            currentPos: newPos,
            updateTime: targetTime,
            prevUpdateTime: prevTime,
            heading: plane.true_track || 0,
            altitude: effectiveAlt,
            velocity: plane.velocity || 0,
            verticalRate: plane.vertical_rate || 0,
            lastSampleTime: Date.now() / 1000
          };
        } else {
          // Update motion data - shift current to previous for smooth interpolation
          const currentProjected = getProjectedPosition(motionData);
          motionData.prevPos = currentProjected;
          motionData.currentPos = newPos;
          // Anchor the new segment to "now" so we don't stall when updates arrive sooner than the previous target time
          motionData.prevUpdateTime = nowJulian;
          motionData.updateTime = Cesium.JulianDate.addSeconds(nowJulian, interpolationDuration, new Cesium.JulianDate());
          motionData.heading = plane.true_track || 0;
          motionData.altitude = effectiveAlt;
          motionData.velocity = plane.velocity || 0;
          motionData.verticalRate = plane.vertical_rate || 0;
          motionData.lastSampleTime = nowSec;
        }
        
        aircraftMotionDataRef.current.set(plane.icao24, motionData);

        // Check if entity exists
        let entity = viewer.entities.getById(plane.icao24);

        // Define rotation property - needs to be available for both create and update paths
        const rotationProperty = new CallbackProperty(() => {
          const data = aircraftMotionDataRef.current.get(plane.icao24);
          const heading = data?.heading ?? plane.true_track ?? 0;
          return billboardRotationFromHeading(CesiumMath.toRadians(heading));
        }, false);

        // Define orientation property - gives the entity a proper 3D world-frame
        // quaternion so camera tracking and label placement work correctly in 3D views.
        const orientationProperty = new CallbackProperty(() => {
          const data = aircraftMotionDataRef.current.get(plane.icao24);
          if (!data) return Cesium.Quaternion.IDENTITY;
          const { quaternion } = computeOrientationFromApiData(
            data.currentPos,
            data.heading,
            data.verticalRate,
            data.velocity
          );
          return quaternion;
        }, false);

        if (!entity) {
          // Create new entity — position callback uses the same phased logic as getProjectedPosition
          const positionProperty = new CallbackProperty(() => {
            const data = aircraftMotionDataRef.current.get(plane.icao24);
            if (!data) return newPos;

            const nowJul = Cesium.JulianDate.now();
            const elapsed = Cesium.JulianDate.secondsDifference(nowJul, data.prevUpdateTime);
            const total = Cesium.JulianDate.secondsDifference(data.updateTime, data.prevUpdateTime) || interpolationDuration;
            const currCarto = Cesium.Cartographic.fromCartesian(data.currentPos);
            const headingRad = Cesium.Math.toRadians(data.heading || 0);
            const speed = data.velocity || 0;
            const climb = data.verticalRate || 0;
            const R = 6378137;

            if (elapsed < total) {
              // Phase 1: smooth lerp from prevPos to currentPos — no dead-reckoning
              const t = Math.max(0, elapsed / total);
              const prevCarto = Cesium.Cartographic.fromCartesian(data.prevPos);
              return Cartesian3.fromRadians(
                prevCarto.longitude + (currCarto.longitude - prevCarto.longitude) * t,
                prevCarto.latitude  + (currCarto.latitude  - prevCarto.latitude)  * t,
                prevCarto.height    + (currCarto.height    - prevCarto.height)    * t
              );
            } else {
              // Phase 2: dead-reckon forward from currentPos — aircraft always moves forward, never back
              const dtSec = Math.min(elapsed - total, 60);
              const dLat = (speed * Math.cos(headingRad) * dtSec) / R;
              const dLon = (speed * Math.sin(headingRad) * dtSec) / (R * Math.max(Math.cos(currCarto.latitude), 1e-6));
              return Cartesian3.fromRadians(
                currCarto.longitude + dLon,
                currCarto.latitude  + dLat,
                currCarto.height    + climb * dtSec
              );
            }
          }, false);

          // Get color based on altitude for enhanced visualization
          const getColorByAltitude = (alt: number) => {
            if (alt < 1000) return Color.RED;           // Low altitude - red
            if (alt < 5000) return Color.YELLOW;        // Medium-low - yellow
            if (alt < 10000) return Color.LIME;         // Medium - green
            if (alt < 20000) return Color.CYAN;         // Medium-high - cyan
            return Color.BLUE;                          // High altitude - blue
          };

          const altitudeColor = getColorByAltitude(altitude);
          const iconUrl = getAircraftIconUrl(plane.category);

          entity = viewer.entities.add({
            id: plane.icao24,
            position: positionProperty,
            // Full 3D orientation: aligns entity with flight path in Follow/Cockpit 3D modes
            orientation: orientationProperty as any,
            billboard: {
              image: iconUrl,
              width: ICON_SIZE,
              height: ICON_SIZE,
              scale: 1,
              rotation: rotationProperty,
              alignedAxis: Cesium.Cartesian3.UNIT_Z,
              translucencyByDistance: new Cesium.NearFarScalar(1.5e2, 1.0, 8.0e6, 0.2)
            },
            properties: {
              callsign: plane.callsign,
              altitude: altitude,
              velocity: plane.velocity,
              heading: plane.true_track
            }
          });

          // Canvas-drawn label companion — browser-identical rendering
          const lblText = plane.callsign || plane.icao24;
          const { url: lblUrl, w: lblW, h: lblH } = makeTextLabel(lblText);
          const lblId = `${plane.icao24}-lbl`;
          if (!viewer.entities.getById(lblId)) {
            viewer.entities.add({
              id: lblId,
              position: positionProperty,
              billboard: {
                image: lblUrl,
                width: lblW,
                height: lblH,
                pixelOffset: new Cesium.Cartesian2(0, -(ICON_SIZE / 2 + lblH / 2 + 4)),
                show: showLabels,
                distanceDisplayCondition: new Cesium.DistanceDisplayCondition(0, 1e7),
                disableDepthTestDistance: Number.POSITIVE_INFINITY
              }
            });
          }

          console.log(`✈ Created entity for ${plane.icao24}`);
        } else {
          // Update existing entity's motion data (position will update via CallbackProperty)
          if (entity.position instanceof CallbackProperty) {
            // Position already updates via callback, just ensure motion data is current
            const lblEnt = viewer.entities.getById(`${plane.icao24}-lbl`);
            if (lblEnt?.billboard) (lblEnt.billboard.show as any) = showLabels;
            if (entity.billboard) {
              entity.billboard.rotation = rotationProperty as any;
              entity.billboard.alignedAxis = Cesium.Cartesian3.UNIT_Z as any;
              entity.billboard.width = ICON_SIZE as any;
              entity.billboard.height = ICON_SIZE as any;
            }
            // Keep orientation in sync with latest motion data
            if (entity.orientation !== undefined) {
              (entity as any).orientation = orientationProperty;
            }
          }
        }

        // Handle flight paths for better visualization
        if (selectedAircraft && plane.icao24 === selectedAircraft.icao24) {
          const path = aircraftPathsRef.current.get(plane.icao24) || [];
          const currentPos = Cartesian3.fromDegrees(plane.longitude, plane.latitude, effectiveAlt);
          path.push(currentPos);
          if (path.length > 100) path.shift(); // Keep 100 positions
          aircraftPathsRef.current.set(plane.icao24, path);
        }

        newPreviousAircraft.set(plane.icao24, plane);
      } catch (error) {
        console.warn(`Error processing aircraft ${plane.icao24}:`, error);
      }
    });

    // Clean up motion data and entities for aircraft no longer in current batch
    // Keep entities around for a short grace period to avoid immediate removal
    const GRACE_PERIOD_MS = 30000; // 30 seconds
    const displayIds = new Set(displayAircraft.map(a => a.icao24));

    // Remove entities not in current batch:
    // - Immediately if previously tracked (slider reduced count, category disabled, etc.)
    // - After grace period only for truly unknown entities
    const entitiesToRemove: any[] = [];
    viewer.entities.values.forEach((entity: Cesium.Entity) => {
      if (entity.id && typeof entity.id === 'string' && !entity.id.startsWith('path-') && !entity.id.endsWith('-lbl') && !displayIds.has(entity.id)) {
        const wasPreviouslyTracked = aircraftCategoryRef.current.has(entity.id as string);
        const lastSeen = lastSeenRef.current.get(entity.id as string) || 0;
        if (wasPreviouslyTracked || Date.now() - lastSeen > GRACE_PERIOD_MS) {
          entitiesToRemove.push(entity);
        }
      }
    });

    entitiesToRemove.forEach(entity => {
      // Remove canvas label companion first
      const lblToRemove = viewer.entities.getById(`${entity.id}-lbl`);
      if (lblToRemove) viewer.entities.remove(lblToRemove);
      viewer.entities.remove(entity);
      // Also delete motion data so fresh aircraft start clean
      if (entity.id) {
        aircraftMotionDataRef.current.delete(entity.id as string);
        lastSeenRef.current.delete(entity.id as string);
        aircraftCategoryRef.current.delete(entity.id as string);
      }
    });

    previousAircraftRef.current = newPreviousAircraft;
    if (updatedCount > 0) {
      console.log(`✈ Updated ${updatedCount}/${displayAircraft.length} aircraft positions (optimized: skipped unchanged)`);
    }

    // Ensure a render so interpolations stay live even when camera is tracking another aircraft
    viewer.scene.requestRender?.();
  }, [aircraft, showLabels, enabledCategories]);

  // Draw flight paths with glow effect
  useEffect(() => {
    if (!viewerRef.current?.cesiumElement) return;
    const viewer = viewerRef.current.cesiumElement;

    if (showPaths && selectedAircraft) {
      const path = aircraftPathsRef.current.get(selectedAircraft.icao24);
      if (path && path.length > 1) {
        const pathId = `path-${selectedAircraft.icao24}`;
        let pathEntity = viewer.entities.getById(pathId);

        if (!pathEntity) {
          pathEntity = viewer.entities.add({
            id: pathId,
            polyline: {
              positions: new CallbackProperty(() => {
                return aircraftPathsRef.current.get(selectedAircraft.icao24) || [];
              }, false),
              width: 4,
              material: new Cesium.PolylineGlowMaterialProperty({
                glowPower: 0.3,
                color: Color.CYAN.withAlpha(0.8)
              }),
              clampToGround: false,
              zIndex: 100
            }
          });
        }
      }
    } else if (selectedAircraft) {
      // Remove path if showPaths is disabled
      const pathId = `path-${selectedAircraft.icao24}`;
      const pathEntity = viewer.entities.getById(pathId);
      if (pathEntity) {
        viewer.entities.remove(pathEntity);
      }
    }
  }, [showPaths, selectedAircraft]);

  const flyToAircraft = (plane: Aircraft) => {
    if (viewerRef.current?.cesiumElement && plane.latitude && plane.longitude) {
      const viewer = viewerRef.current.cesiumElement;
      try {
        const entity = viewer.entities.getById(plane.icao24);
        if (entity) {
          viewer.flyTo(entity, {
            duration: 2,
            offset: new Cesium.HeadingPitchRange(0, -90, 5000)
          });
        }
      } catch (error) {
        console.warn(`Failed to fly to aircraft ${plane.icao24}:`, error);
      }
    }
  };

  const followAircraft = (plane: Aircraft) => {
    if (viewerRef.current?.cesiumElement && plane.latitude && plane.longitude) {
      try {
        const viewer = viewerRef.current.cesiumElement;
        const entity = viewer.entities.getById(plane.icao24);

        if (entity) {
          // Set trackedEntity so camera follows smoothly without repeated flyTo calls
          // This allows Cesium to handle continuous smooth tracking automatically
          const wasTracking = viewer.trackedEntity === entity;
          viewer.trackedEntity = entity as any;

          // Only use a quick initial flyTo once when tracking starts (not already tracking this entity)
          if (!wasTracking) {
            // heading: 0 = entity-relative "directly behind the aircraft along its flight path"
            // pitch: -30° = looking down at an angle (matches double-click follow behavior)
            // On-ground aircraft get a much closer zoom (~500m) for airport-level detail
            const range = plane.on_ground ? 500 : 5000;
            const offset = new Cesium.HeadingPitchRange(0, Cesium.Math.toRadians(-30), range);
            viewer.flyTo(entity, { duration: 2.0, offset });
          }
        } else {
          // Fallback: entity not created yet - position camera manually but don't animate repeatedly
          if (!viewer.trackedEntity) {
            const aircraftPosition = Cartesian3.fromDegrees(
              plane.longitude,
              plane.latitude,
              (plane.baro_altitude || 0) + 1000
            );
            viewer.camera.setView({
              destination: aircraftPosition,
              orientation: {
                heading: Cesium.Math.toRadians(plane.true_track || 0),
                pitch: Cesium.Math.toRadians(-30),
                roll: 0
              },
              duration: 0.5
            });
          }
        }
      } catch (error) {
        console.warn(`Failed to follow aircraft ${plane.icao24}:`, error);
      }
    }
  };

  const setCockpitView = (plane: Aircraft) => {
    if (viewerRef.current?.cesiumElement && plane.latitude && plane.longitude) {
      try {
        const viewer = viewerRef.current.cesiumElement;
        const entity = viewer.entities.getById(plane.icao24);

        // Cockpit view: position camera *inside* the aircraft so it's out of view.
        // Camera animates along the aircraft's current position with its heading.
        const heading = Cesium.Math.toRadians(plane.true_track || 0);

        if (entity) {
          // Hide the aircraft entity since we're inside it in cockpit view
          entity.billboard.show = false;
          const cockpitLbl = viewer.entities.getById(`${plane.icao24}-lbl`);
          if (cockpitLbl?.billboard) (cockpitLbl.billboard.show as any) = false;
        }

        // Position camera at aircraft current position (inside the aircraft)
        const aircraftPosition = Cartesian3.fromDegrees(
          plane.longitude,
          plane.latitude,
          (plane.baro_altitude || 0) + 5 // Just inside aircraft
        );

        // Snap to initial cockpit position quickly
        viewer.camera.setView({
          destination: aircraftPosition,
          orientation: {
            heading: heading,
            pitch: Cesium.Math.toRadians(0),
            roll: 0
          },
          duration: 0.5
        });
      } catch (error) {
        console.warn(`Failed to set cockpit view for ${plane.icao24}:`, error);
      }
    }
  };

  const setApproachView = (plane: Aircraft, initial: boolean = false) => {
    if (viewerRef.current?.cesiumElement && plane.latitude && plane.longitude) {
      const viewer = viewerRef.current.cesiumElement;
      const camera = viewer.camera;

      // 2 km altitude, straight top-down in SCENE2D (flat map) - same behaviour as satellite zoom
      const destination = Cartesian3.fromDegrees(plane.longitude, plane.latitude, 2000);
      const orientation = {
        heading: 0,
        pitch: Cesium.Math.toRadians(-90),
        roll: 0
      };

      if (initial) {
        // Smooth fly-in animation on first entry
        camera.flyTo({ destination, orientation, duration: 1.0 });
      } else {
        // Silent update for continuous tracking (no animation jitter)
        camera.setView({ destination, orientation });
      }
    }
  };

  const focusSatelliteView = (plane?: Aircraft, height: number = 20000000) => {
    if (!viewerRef.current?.cesiumElement) return;

    const viewer = viewerRef.current.cesiumElement;
    const camera = viewer.camera;

    if (plane && plane.latitude && plane.longitude) {
      // If aircraft is selected, center on it at the given height
      // Mark animating so the rAF loop doesn't fight the fly-to
      satelliteAnimatingRef.current = true;
      camera.flyTo({
        destination: Cartesian3.fromDegrees(plane.longitude, plane.latitude, height),
        orientation: {
          heading: 0,
          pitch: Cesium.Math.toRadians(-90),
          roll: 0
        },
        duration: 0.8,
        complete: () => {
          satelliteAnimatingRef.current = false;
        },
        cancel: () => {
          satelliteAnimatingRef.current = false;
        }
      });
    } else {
      // No aircraft selected - use current view center or default location
      const currentPos = camera.positionCartographic;
      const longitude = Cesium.Math.toDegrees(currentPos.longitude);
      const latitude = Cesium.Math.toDegrees(currentPos.latitude);
      
      camera.flyTo({
        destination: Cartesian3.fromDegrees(longitude, latitude, height),
        orientation: {
          heading: 0,
          pitch: Cesium.Math.toRadians(-90),
          roll: 0
        },
        duration: 0.8
      });
    }
  };

  // Fly to selected aircraft when selection changes — only in Global 3D view
  // Satellite, approach, follow and cockpit all manage their own camera behaviour
  useEffect(() => {
    if (selectedAircraft && viewMode === 'global') {
      flyToAircraft(selectedAircraft);
    }
  }, [selectedAircraft, viewMode]);

  // Handle view mode changes
  useEffect(() => {
    if (!viewerRef.current?.cesiumElement) return;

    const viewer = viewerRef.current.cesiumElement;
    const scene = viewer.scene;
    const camera = viewer.camera;

    switch (viewMode) {
      case 'global':
        // Default global view
        // Stop tracking any entity and re-show all aircraft
        viewer.trackedEntity = undefined as any;
        // Reset camera transform in case it was bound to a tracked entity
        camera.lookAtTransform(Cesium.Matrix4.IDENTITY);
        viewer.entities.values.forEach((entity: any) => {
          if (entity.billboard) entity.billboard.show = entity.id?.endsWith('-lbl') ? showLabels : true;
        });
        camera.setView({
          destination: Cartesian3.fromDegrees(0, 0, 10000000)
        });
        scene.mode = Cesium.SceneMode.SCENE3D;
        break;

      case 'follow':
        // Ensure we're in 3D mode (may be coming from 2D approach/satellite)
        scene.mode = Cesium.SceneMode.SCENE3D;
        // Re-show aircraft before following
        viewer.entities.values.forEach((entity: any) => {
          if (entity.billboard) entity.billboard.show = entity.id?.endsWith('-lbl') ? showLabels : true;
        });
        if (selectedAircraft && selectedAircraft.latitude && selectedAircraft.longitude) {
          followAircraft(selectedAircraft);
        }
        break;

      case 'cockpit':
        // Ensure we're in 3D mode (may be coming from 2D approach/satellite)
        scene.mode = Cesium.SceneMode.SCENE3D;
        // Clear tracking first
        viewer.trackedEntity = undefined as any;
        // Hide all aircraft billboards/labels before setting cockpit view
        viewer.entities.values.forEach((entity: any) => {
          if (entity.billboard) entity.billboard.show = false;
        });
        if (selectedAircraft && selectedAircraft.latitude && selectedAircraft.longitude) {
          setCockpitView(selectedAircraft);
        }
        break;

      case 'approach':
        // Switch to flat 2D map then fly-in to selected aircraft — identical to satellite double-click
        viewer.trackedEntity = undefined as any;
        viewer.entities.values.forEach((entity: any) => {
          if (entity.billboard) entity.billboard.show = entity.id?.endsWith('-lbl') ? showLabels : true;
        });
        scene.mode = Cesium.SceneMode.SCENE2D;
        if (selectedAircraft && selectedAircraft.latitude && selectedAircraft.longitude) {
          // Reuse focusSatelliteView for the exact same smooth flyTo animation
          focusSatelliteView(selectedAircraft, 2000);
        }
        break;

      case 'satellite':
        // Only do full entry setup when actually switching INTO satellite mode.
        // If we're already in satellite and selectedAircraft/showLabels changed,
        // do nothing — the double-click handler manages follow/zoom directly.
        if (prevViewModeRef.current !== 'satellite') {
          viewer.trackedEntity = undefined as any;
          viewer.entities.values.forEach((entity: any) => {
            if (entity.billboard) entity.billboard.show = entity.id?.endsWith('-lbl') ? showLabels : true;
          });
          scene.mode = Cesium.SceneMode.SCENE2D;
          satelliteFollowRef.current = null;
          focusSatelliteView(); // wide entry view
        } else {
          // Already in satellite — just keep labels in sync, don't touch camera
          viewer.entities.values.forEach((entity: any) => {
            if (entity.id?.endsWith('-lbl') && entity.billboard) (entity.billboard.show as any) = showLabels;
          });
        }
        break;
    }
    prevViewModeRef.current = viewMode;
  }, [viewMode, selectedAircraft, showLabels]);

      // Latch aircraftEverLoaded — once aircraft arrive it never goes false again
      useEffect(() => {
        if (aircraft.length > 0) {
          setAircraftEverLoaded(true);
        }
      }, [aircraft.length]);

      // Keep isFullscreen in sync when user exits via Escape key or browser UI
      useEffect(() => {
        const handler = () => setIsFullscreen(!!document.fullscreenElement);
        document.addEventListener('fullscreenchange', handler);
        return () => document.removeEventListener('fullscreenchange', handler);
      }, []);

      // Toggle satellite/global hint when entering/leaving those modes
      useEffect(() => {
        if (viewMode === 'satellite') {
          setShowSatelliteHint(true);
          setShowGlobalHint(false);
        } else if (viewMode === 'global') {
          setShowGlobalHint(true);
          setShowSatelliteHint(false);
        } else {
          setShowSatelliteHint(false);
          setShowGlobalHint(false);
        }
      }, [viewMode]);

      // Handle double-click: in satellite mode pick entity and select aircraft in Live Aircraft menu
      useEffect(() => {
        const viewer = viewerRef.current?.cesiumElement;
        if (!viewer) return;

        const handler = new Cesium.ScreenSpaceEventHandler(viewer.scene.canvas);
        handler.setInputAction((event: any) => {
          if (viewMode === 'satellite') {
            setShowSatelliteHint(false);

            // Pick the entity under the cursor
            const picked = viewer.scene.pick(event.position);
            if (picked && picked.id) {
              const rawId = typeof picked.id === 'string' ? picked.id : picked.id.id;
              // Strip canvas-label suffix so clicking a label works identically to clicking the icon
              const entityId = typeof rawId === 'string' && rawId.endsWith('-lbl') ? rawId.slice(0, -4) : rawId;
              const clickedAircraft = aircraft.find(a => a.icao24 === entityId);
              if (clickedAircraft) {
                // Immediately start following — don't wait for React state update
                satelliteFollowRef.current = clickedAircraft.icao24;
                satelliteZoomRef.current = 4000; // reset to 4 km on new selection
                focusSatelliteView(clickedAircraft, 4000);
                if (onSelectAircraft) onSelectAircraft(clickedAircraft);
              }
            }
          } else if (viewMode === 'global') {
            setShowGlobalHint(false);
            // In Global 3D: double-click selects the aircraft, switches to Follow 3D, and starts tracking
            const picked = viewer.scene.pick(event.position);
            if (picked && picked.id) {
              const rawId = typeof picked.id === 'string' ? picked.id : picked.id.id;
              // Strip canvas-label suffix so clicking a label works identically to clicking the icon
              const entityId = typeof rawId === 'string' && rawId.endsWith('-lbl') ? rawId.slice(0, -4) : rawId;
              const clickedAircraft = aircraft.find(a => a.icao24 === entityId);
              if (clickedAircraft) {
                if (onSelectAircraft) onSelectAircraft(clickedAircraft);
                if (onViewModeChange) onViewModeChange('follow');
                // Start follow immediately without waiting for React re-render
                followAircraft(clickedAircraft);
              }
            }
          }
        }, Cesium.ScreenSpaceEventType.LEFT_DOUBLE_CLICK);

        return () => handler.destroy();
      }, [viewMode, aircraft, onSelectAircraft]);

  // Update camera for dynamic view modes (not approach — that uses rAF loop below)
  useEffect(() => {
    if (!selectedAircraft || !['follow', 'cockpit'].includes(viewMode)) return;

    const updateCamera = () => {
      switch (viewMode) {
        case 'follow':
          followAircraft(selectedAircraft);
          break;
        case 'cockpit':
          setCockpitView(selectedAircraft);
          break;
      }
    };

    updateCamera();
  }, [aircraft, viewMode, selectedAircraft]);

  // Continuous camera updates for dynamic view modes
  useEffect(() => {
    if (!['follow', 'cockpit', 'approach', 'satellite'].includes(viewMode)) return;
    if (viewMode !== 'satellite' && !selectedAircraft) return;

    if (viewMode === 'cockpit') {
      // Cockpit: bind camera to the entity's interpolated position so motion stays smooth between API polls
      let animationFrameId: number;

      const animateCockpitCamera = () => {
        const viewer = viewerRef.current?.cesiumElement;
        if (!viewer) {
          animationFrameId = requestAnimationFrame(animateCockpitCamera);
          return;
        }

        const entity = viewer.entities.getById(selectedAircraft!.icao24);
        if (entity && entity.position) {
          const now = Cesium.JulianDate.now();
          const pos = entity.position.getValue(now);
          if (pos) {
            // Use the latest heading stored during motion updates to avoid snapping
            const motion = aircraftMotionDataRef.current.get(selectedAircraft!.icao24);
            const heading = Cesium.Math.toRadians(motion?.heading || selectedAircraft!.true_track || 0);

            // Place camera at interpolated position with a slight offset to avoid clipping inside the model
            const carto = Cesium.Cartographic.fromCartesian(pos);
            const offsetPos = Cartesian3.fromRadians(
              carto.longitude,
              carto.latitude,
              (carto.height || 0) + 5
            );

            viewer.camera.setView({
              destination: offsetPos,
              orientation: {
                heading,
                pitch: Cesium.Math.toRadians(0),
                roll: 0
              }
            });
          }
        }

        animationFrameId = requestAnimationFrame(animateCockpitCamera);
      };

      animationFrameId = requestAnimationFrame(animateCockpitCamera);
      return () => cancelAnimationFrame(animationFrameId);
    } else if (viewMode === 'approach') {
      // Approach 2D: use requestAnimationFrame to read interpolated entity position every frame
      // so camera follows smoothly without 500ms snap intervals
      let animationFrameId: number;

      // Reset zoom to initial 2km when entering approach mode
      approachZoomRef.current = 2000;

      const animateApproachCamera = () => {
        const viewer = viewerRef.current?.cesiumElement;
        if (!viewer) {
          animationFrameId = requestAnimationFrame(animateApproachCamera);
          return;
        }

        // Read current camera height so user scroll zoom is preserved
        const currentCameraHeight = viewer.camera.positionCartographic.height;
        if (currentCameraHeight > 0) {
          approachZoomRef.current = currentCameraHeight;
        }

        const entity = viewer.entities.getById(selectedAircraft!.icao24);
        if (entity && entity.position) {
          const now = Cesium.JulianDate.now();
          const pos = entity.position.getValue(now);
          if (pos) {
            const carto = Cesium.Cartographic.fromCartesian(pos);
            const overheadPos = Cartesian3.fromRadians(
              carto.longitude,
              carto.latitude,
              approachZoomRef.current // preserve user's zoom level
            );
            viewer.camera.setView({
              destination: overheadPos,
              orientation: {
                heading: 0,
                pitch: Cesium.Math.toRadians(-90),
                roll: 0
              }
            });
          }
        }

        animationFrameId = requestAnimationFrame(animateApproachCamera);
      };

      animationFrameId = requestAnimationFrame(animateApproachCamera);
      return () => cancelAnimationFrame(animationFrameId);
    } else if (viewMode === 'satellite') {
      // Satellite 2D: rAF loop that re-centers camera on the followed aircraft every frame
      let animationFrameId: number;

      const animateSatelliteCamera = () => {
        const viewer = viewerRef.current?.cesiumElement;
        if (!viewer) {
          animationFrameId = requestAnimationFrame(animateSatelliteCamera);
          return;
        }

        if (satelliteFollowRef.current) {
          // Pause tracking while the initial fly-to animation is running to avoid fighting it
          if (!satelliteAnimatingRef.current) {
            // Preserve user scroll zoom each frame (only when steady state)
            const currentHeight = viewer.camera.positionCartographic.height;
            if (currentHeight > 0) {
              satelliteZoomRef.current = currentHeight;
            }

            const entity = viewer.entities.getById(satelliteFollowRef.current);
            if (entity && entity.position) {
              const pos = entity.position.getValue(Cesium.JulianDate.now());
              if (pos) {
                const carto = Cesium.Cartographic.fromCartesian(pos);
                viewer.camera.setView({
                  destination: Cartesian3.fromRadians(
                    carto.longitude,
                    carto.latitude,
                    satelliteZoomRef.current
                  ),
                  orientation: {
                    heading: 0,
                    pitch: Cesium.Math.toRadians(-90),
                    roll: 0
                  }
                });
              }
            }
          }
        }

        animationFrameId = requestAnimationFrame(animateSatelliteCamera);
      };

      animationFrameId = requestAnimationFrame(animateSatelliteCamera);
      return () => cancelAnimationFrame(animationFrameId);
    } else {
      // For follow: use slower interval updates
      const intervalId = setInterval(() => {
        const currentAircraft = aircraft.find(a => a.icao24 === selectedAircraft!.icao24);
        if (currentAircraft && currentAircraft.latitude && currentAircraft.longitude) {
          if (viewMode === 'follow' && viewerRef.current?.cesiumElement) {
            const viewer = viewerRef.current.cesiumElement;
            const entity = viewer.entities.getById(currentAircraft.icao24);
            if (entity && viewer.trackedEntity !== entity) {
              viewer.trackedEntity = entity as any;
            }
          }
        }
      }, 500);

      return () => clearInterval(intervalId);
    }
  }, [viewMode, selectedAircraft, aircraft]);

  // Update zoom altitude display on every render frame
  useEffect(() => {
    const viewer = viewerRef.current?.cesiumElement;
    if (!viewer) return;
    const removeListener = viewer.scene.postRender.addEventListener(() => {
      const height = viewer.camera.positionCartographic.height;
      setZoomAltitude(Math.round(height / 1000)); // metres -> km
    });
    return () => removeListener();
  }, [viewerRef.current?.cesiumElement]);

  return (
    <CesiumErrorBoundary>
      <div className="cesium-container h-full">
        {showLoadingOverlay && (
          <div className="absolute inset-0 z-20 flex items-center justify-center bg-black/80 text-white">
            <div className="text-center px-6 py-4 rounded-lg bg-black/60 border border-gray-700 shadow-lg">
              <div className="w-10 h-10 border-4 border-white/30 border-t-white rounded-full animate-spin mx-auto mb-3" />
              <h2 className="text-lg font-semibold mb-1">Loading Cesium Globe...</h2>
              <p className="text-sm text-gray-300">{loadingMessage}</p>
            </div>
          </div>
        )}
        <CesiumViewerComponent
          ref={viewerRef}
          full
          timeline={false}
          animation={false}
          shouldAnimate
          requestRenderMode={false}
          baseLayerPicker={false}
          geocoder={false}
          homeButton={false}
          infoBox={false}
          navigationHelpButton={false}
          sceneModePicker={false}
          selectionIndicator={false}
          creditContainer={creditContainerRef.current}
        />
        {/* Back button — shown when an aircraft is selected */}
        {selectedAircraft && (
          <button
            onClick={() => onDeselectAircraft?.()}
            className="absolute top-4 left-4 flex items-center gap-2 bg-black/70 hover:bg-black/90 text-white px-3 py-2 rounded-lg text-sm font-medium transition-colors z-10"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M19 12H5M12 5l-7 7 7 7"/>
            </svg>
            Back
          </button>
        )}

        {/* Aircraft count + fullscreen button — top right */}
        <div className="absolute top-4 right-4 flex flex-col items-end gap-2">
          <div className="bg-black/70 text-white p-2 rounded text-sm pointer-events-none">
            Showing {Math.min(aircraft.length, maxDisplayCount)} of {aircraft.length} aircraft
          </div>
          {/* Fullscreen button — mobile/tablet only */}
          <button
            onClick={() => {
              if (!document.fullscreenElement) {
                document.documentElement.requestFullscreen();
                setIsFullscreen(true);
              } else {
                document.exitFullscreen();
                setIsFullscreen(false);
              }
            }}
            className="lg:hidden bg-[#303336] border border-[#444] text-[#edffff] fill-[#edffff] rounded w-[29px] h-[29px] flex items-center justify-center hover:bg-[#48b] hover:border-[#aef] hover:shadow-[0_0_8px_white] transition-all z-10"
            title={isFullscreen ? 'Exit fullscreen' : 'Enter fullscreen'}
          >
            <svg width="15" height="15" viewBox="0 0 128 128" fill="currentColor">
              {isFullscreen ? (
                <path d="M52 17.59L44.72 24.88L64 44.16L83.28 24.88L76 17.59L76 17.59L110.41 17.59L110.41 52L103.12 44.72L83.84 64L103.12 83.28L110.41 76L110.41 110.41L76 110.41L83.28 103.12L64 83.84L44.72 103.12L52 110.41L17.59 110.41L17.59 76L24.88 83.28L44.16 64L24.88 44.72L17.59 52L17.59 17.59Z" />
              ) : (
                <path d="M 83.96875 17.5625 L 83.96875 17.59375 L 76.65625 24.875 L 97.09375 24.96875 L 76.09375 45.96875 L 81.9375 51.8125 L 102.78125 30.9375 L 102.875 51.15625 L 110.15625 43.875 L 110.1875 17.59375 L 83.96875 17.5625 z M 44.125 17.59375 L 17.90625 17.625 L 17.9375 43.90625 L 25.21875 51.1875 L 25.3125 30.96875 L 46.15625 51.8125 L 52 45.96875 L 31 25 L 51.4375 24.90625 L 44.125 17.59375 z M 46.0625 76.03125 L 25.1875 96.875 L 25.09375 76.65625 L 17.8125 83.9375 L 17.8125 110.21875 L 44 110.25 L 51.3125 102.9375 L 30.90625 102.84375 L 51.875 81.875 L 46.0625 76.03125 z M 82 76.15625 L 76.15625 82 L 97.15625 103 L 76.71875 103.0625 L 84.03125 110.375 L 110.25 110.34375 L 110.21875 84.0625 L 102.9375 76.8125 L 102.84375 97 L 82 76.15625 z" />
              )}
            </svg>
          </button>
        </div>

        {/* Live aircraft loading indicator — bottom left, shows only until first data arrives */}
        {!aircraftEverLoaded && (
          <div className="absolute bottom-4 left-4 bg-black/70 text-white p-2 rounded text-sm pointer-events-none animate-pulse">
            Live Aircrafts Loading...
          </div>
        )}

        {/* Cockpit overlay: center bottom aircraft identifier when in cockpit view */}
        {viewMode === 'cockpit' && selectedAircraft && (
          <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 lg:top-auto lg:bottom-6 lg:translate-y-0 bg-black/70 text-white px-4 py-2 rounded-lg text-sm font-semibold pointer-events-none">
            <div className="text-center">
              {selectedAircraft.callsign ? selectedAircraft.callsign.trim() : selectedAircraft.icao24}
            </div>
          </div>
        )}

        {viewMode === 'satellite' && showSatelliteHint && (
          <div className="hidden lg:block absolute left-1/2 bottom-4 transform -translate-x-1/2 bg-black/70 text-white px-4 py-2 rounded-lg text-sm font-semibold pointer-events-none">
            Double click on your desired aircraft
          </div>
        )}

        {viewMode === 'global' && showGlobalHint && (
          <div className="hidden lg:block absolute left-1/2 bottom-4 transform -translate-x-1/2 bg-black/70 text-white px-4 py-2 rounded-lg text-sm font-semibold pointer-events-none">
            Double click on your desired aircraft
          </div>
        )}

        {/* Right-side overlay column: zoom/altitude widget only */}
        <div className="absolute right-4 top-1/2 -translate-y-1/2 flex flex-col items-center gap-2">

          {/* Zoom level indicator */}
          {zoomAltitude !== null && (
            <div className="flex flex-col items-center gap-2 pointer-events-none">
              <div className="bg-black/70 text-white px-3 py-2 rounded-lg text-xs font-mono text-center">
                <div className="text-gray-400 text-[10px] uppercase tracking-widest mb-1">Altitude</div>
                <div className="text-green-400 font-bold text-sm">
                  {zoomAltitude >= 1000
                    ? `${(zoomAltitude / 1000).toFixed(1)}k km`
                    : `${zoomAltitude.toLocaleString()} km`}
                </div>
              </div>
              {/* Visual zoom bar */}
              <div className="bg-black/70 rounded-lg p-2 flex flex-col items-center gap-1">
                <div className="text-gray-500 text-[9px]">+</div>
                <div className="w-2 bg-gray-700 rounded-full overflow-hidden" style={{height: '80px'}}>
                  <div
                    className="w-full bg-green-400 rounded-full transition-all duration-300"
                    style={{
                      height: `${Math.max(2, Math.min(100, 100 - (Math.log10(Math.max(zoomAltitude, 1)) / Math.log10(20000)) * 100))}%`,
                      marginTop: 'auto'
                    }}
                  />
                </div>
                <div className="text-gray-500 text-[9px]">−</div>
              </div>
            </div>
          )}
        </div>
      </div>
    </CesiumErrorBoundary>
  );
};

export default CesiumViewer;